noncompliant:
void f(int i, int j);

void g() {
  int i = 0;
  f(++i, ++i); // Noncompliant, the call could either be f(1,2) or f(2,1) (since C++17) or undefined behavior (before C++17)
}

compliant:
void f(int i, int j);

void g() {
  int i = 0;
  int first = ++i;
  int second = ++i;
  f(first, second); // Compliant, evaluation order is clear
}

void f(int i, int j);

void g() {
  int i = 0;
  f(1, 2); // Compliant, using constants
}
